const MONAD_HEADER = `// SPDX-License-Identifier: MIT
// Generated by Monad Build.exe — NX Terminal
// Target: Monad Testnet (Chain ID 10143)
// Compiler: solc ^0.8.28, evmVersion: "prague"
//
// MONAD OPTIMIZATION NOTES:
// - Monad charges gas based on gas LIMIT, not gas used. Set tight limits.
// - Cold SLOAD costs 8,100 gas (vs 2,100 on Ethereum). Cache storage reads.
// - Cold account access costs 10,100 gas. Minimize cross-contract cold calls.
// - Max contract size: 128 KB (vs 24.5 KB on Ethereum).
`;

export function assembleContract({ imports, contractName, inheritance, constructorArgs, constructorBody, functions, stateVars }) {
  const importLines = imports.map(i => `import "${i}";`).join('\n');
  const inheritanceStr = inheritance.length ? ` is ${inheritance.join(', ')}` : '';
  const argsStr = constructorArgs?.length ? constructorArgs.join(', ') : '';
  const superCalls = [];

  if (inheritance.includes('ERC20') && constructorArgs?.some(a => a.includes('name_'))) {
    superCalls.push('ERC20(name_, symbol_)');
  }
  if (inheritance.includes('ERC721') && constructorArgs?.some(a => a.includes('name_'))) {
    superCalls.push('ERC721(name_, symbol_)');
  }
  if (inheritance.includes('ERC1155')) {
    superCalls.push('ERC1155(uri_)');
  }
  if (inheritance.includes('Ownable')) {
    superCalls.push('Ownable(initialOwner)');
  }

  const superStr = superCalls.length ? ` ${superCalls.join(' ')}` : '';
  const bodyStr = constructorBody?.length ? `\n        ${constructorBody.join('\n        ')}` : '';
  const stateStr = stateVars?.length ? `\n    ${stateVars.join('\n    ')}\n` : '';
  const funcStr = functions?.length ? `\n\n    ${functions.join('\n\n    ')}` : '';

  return `${MONAD_HEADER}
pragma solidity ^0.8.28;

${importLines}

contract ${contractName}${inheritanceStr} {${stateStr}
    constructor(${argsStr})${superStr} {${bodyStr}
    }${funcStr}
}
`;
}

export function ownerModifier(accessControl) {
  return accessControl === 'roles' ? 'onlyRole(DEFAULT_ADMIN_ROLE)' : 'onlyOwner';
}

export function pauseGuard(features) {
  return features.pausable ? 'whenNotPaused ' : '';
}
